final:
module RefModule(
    A,
    B,
    SEL,
    Y
);// Module ports
    input  A;
    input  B;
    input  SEL;
    output Y;

    // Local signals
    wire not_SEL;

    // Invert SEL signal
    not not_SEL_inst (
        not_SEL,
        SEL
    );

    // Multiplexer
  wire temp1_(SEL & A) = (SEL & A);
  wire temp2_(not_SEL & B) = (not_SEL & B);
  assign Y = temp1_(SEL & A) | temp2_(not_SEL & B);

endmodule
